def most_common_word(s):
    if not s:
        return ''

    word_count = {}
    words = s.lower().split()

    for word in words:
        word_count[word] = word_count.get(word, 0) + 1

    most_common = max(word_count.items(), key=lambda x: (-x[1], x[0]))
    return most_common[0]
